// src/contexts/ProductContext.tsx
import React, {
    createContext,
    useContext,
    useState,
    useEffect,
} from "react";

export interface ProductHistoryEntry {
    date: string;
    price: number;
    stock: number;
}

export interface Product {
    id: number;
    name: string;
    category: string;
    stock: number;
    weight: number;
    price: number;
    threshold: number;
    description?: string;
    createdAt: string;
    history: ProductHistoryEntry[];
}

interface ProductContextType {
    products: Product[];
    addProduct: (p: Omit<Product, "id" | "threshold" | "history">) => void;
    updateProductPriceAndStock: (
        id: number,
        price: number,
        stock: number,
        date: string
    ) => void;
    updateProduct: (updated: Product) => void;
    deleteProduct: (id: number) => void;
}

const ProductContext = createContext<ProductContextType | undefined>(undefined);

export const ProductsProvider: React.FC<{
    children: React.ReactNode;
}> = ({ children }) => {
    const STORAGE_KEY = "inventory";
    const [products, setProducts] = useState<Product[]>(() => {
        const stored = localStorage.getItem(STORAGE_KEY);
        return stored ? JSON.parse(stored) : [];
    });

    // persist
    useEffect(() => {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(products));
    }, [products]);

    const addProduct = (
        newProd: Omit<Product, "id" | "threshold" | "history">
    ) => {
        const id = products.length ? Math.max(...products.map((p) => p.id)) + 1 : 1;
        const entry: ProductHistoryEntry = {
            date: newProd.createdAt,
            price: newProd.price,
            stock: newProd.stock,
        };
        setProducts((prev) => [
            ...prev,
            {
                ...newProd,
                id,
                threshold: newProd.stock,
                history: [entry],
            },
        ]);
    };

    const updateProductPriceAndStock = (
        id: number,
        price: number,
        stock: number,
        date: string
    ) => {
        setProducts((prev) =>
            prev.map((p) =>
                p.id !== id
                    ? p
                    : {
                        ...p,
                        price,
                        stock,
                        history: [...p.history, { date, price, stock }],
                    }
            )
        );
    };

    const updateProduct = (updated: Product) => {
        setProducts((prev) =>
            prev.map((p) => {
                if (p.id !== updated.id) return p;

                // keep the tail of history but reset the first entry to new createdAt
                const newHistory: ProductHistoryEntry[] = p.history.map((h, i) =>
                    i === 0
                        ? { date: updated.createdAt, price: updated.price, stock: updated.stock }
                        : h
                );
                return {
                    ...updated,
                    threshold: updated.stock,
                    history: newHistory,
                };
            })
        );
    };

    const deleteProduct = (id: number) => {
        setProducts((prev) => prev.filter((p) => p.id !== id));
    };

    return (
        <ProductContext.Provider
            value={{
                products,
                addProduct,
                updateProductPriceAndStock,
                updateProduct,
                deleteProduct,
            }}
        >
            {children}
        </ProductContext.Provider>
    );
};

export function useProducts() {
    const ctx = useContext(ProductContext);
    if (!ctx) throw new Error("useProducts must be inside a ProductsProvider");
    return ctx;
}
